import{_ as e,o as i,c as a,ag as n}from"./chunks/framework.eQLvDOR_.js";const u=JSON.parse('{"title":"anti-ai-writing-style","description":"","frontmatter":{"title":"anti-ai-writing-style","concept":"反 AI 写作风格","concept_id":"anti-ai-writing-style","aliases":["Anti-AI Writing Style"],"sources":["02_Library/AI_Prompt_Engineering/[AI_Prompt_Engineering] How to set up Claude Cowork (the April 2026 update)_.md"],"related_concepts":["[[context-optimization]]"],"created_at":"2026-04-18","last_compiled":"2026-04-18"},"headers":[],"relativePath":"wiki/concepts/anti-ai-writing-style.md","filePath":"wiki/concepts/anti-ai-writing-style.md","lastUpdated":null}'),r={name:"wiki/concepts/anti-ai-writing-style.md"};function o(l,t,s,c,d,p){return i(),a("div",null,[...t[0]||(t[0]=[n('<h1 id="反-ai-写作风格-anti-ai-writing-style" tabindex="-1">反 AI 写作风格 (Anti-AI Writing Style) <a class="header-anchor" href="#反-ai-写作风格-anti-ai-writing-style" aria-label="Permalink to &quot;反 AI 写作风格 (Anti-AI Writing Style)&quot;">​</a></h1><h2 id="定义" tabindex="-1">定义 <a class="header-anchor" href="#定义" aria-label="Permalink to &quot;定义&quot;">​</a></h2><p>一种应对大型语言模型“陈词滥调”和“套路化语气”策略。通过建立专门的负面指示词黑名单（通常保存在独立文件如 <code>writing_rules.md</code> 中），明确禁止 AI 使用各类常见的 AI 味词汇和句形。</p><h2 id="核心要点" tabindex="-1">核心要点 <a class="header-anchor" href="#核心要点" aria-label="Permalink to &quot;核心要点&quot;">​</a></h2><ul><li><strong>黑名单机制</strong>：不要仅仅说“请自然地写作”，而是明确指出绝对不允许涉及的词汇，诸如：&#39;delve&#39;, &#39;ensure&#39;, &#39;moreover&#39;, &#39;embrace&#39; 等。（来源：<a href="/s/webclips/library/AI_Prompt_Engineering/AI_Prompt_Engineering - How to set up Claude Cowork (the April 2026 update)_.html">[AI_Prompt_Engineering] How to set up Claude Cowork (the April 2026 update)_.md</a>）</li><li><strong>禁止过度总结</strong>：AI 喜欢在文章开头总结，并在末尾说“In conclusion...”。可以通过指令强制禁止“Intro and Outro”。</li></ul><h2 id="实践指南" tabindex="-1">实践指南 <a class="header-anchor" href="#实践指南" aria-label="Permalink to &quot;实践指南&quot;">​</a></h2><p>在给 Agent 的全局 System 指南中，包含一份具体的负面风格清单源文件，利用诸如 <code>Never use X, Y, Z words</code> 的形式来纠正 AI 的行文习惯，这是获取拟人化自然输出的最强力手段。</p><h2 id="关联概念" tabindex="-1">关联概念 <a class="header-anchor" href="#关联概念" aria-label="Permalink to &quot;关联概念&quot;">​</a></h2><ul><li><a href="/s/webclips/wiki/concepts/context-optimization.html">context-optimization</a> — 这是长期背景注入中的一部分优化点。</li></ul>',9)])])}const h=e(r,[["render",o]]);export{u as __pageData,h as default};
